  1→import './profilepostcards.css';
  2→import '../../../RepostModal/repostmodal.css';
  3→import { createPortal } from 'react-dom';
  4→import { useAuth } from '../../../../Context/useAuth';
  5→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
  6→import { deleteJournal, deleteJournalImage, getUserJournals, updateRepostCaption } from '../../../../../API/Api';
  7→import { useEffect, useCallback } from 'react';
  8→import { FadeLoader, MoonLoader } from 'react-spinners';
  9→import ParseContent from '../parseData';
 10→import { useInView } from 'react-intersection-observer';
 11→import { useState } from 'react';
 12→import { AnimatePresence, motion } from 'framer-motion';
 13→import { handleCLickContent } from '../../../../../helpers/handleClicks';
 14→import { useNavigate } from 'react-router-dom';
 15→import EditJournal from './editJournal';
 16→import { useAddViewsMutation, useUpdateJournalPrivacyMutation } from '../../../../utils/useMutation';
 17→import VerifiedBadge from '../../../Badge/VerifiedBadge';
 18→import { handleImageFallback } from '../../../../utils/handleImageFallback';
 19→import { getCanvasPreview } from '../../../../utils/canvasDoc';
 20→import CanvasPreview from '../CanvasPreview/CanvasPreview';
 21→
 22→const ProfilePostCards = () =>{
 23→    const queryClient = useQueryClient();
 24→    const {user, session}= useAuth();
 25→    const navigate = useNavigate();
 26→
 27→    const [showEditor, setShowEditor] = useState(null);
 28→
 29→    const {ref, inView} = useInView({
 30→        threshold: 0.2
 31→    })
 32→
 33→    const settingsList = [
 34→        {
 35→            label: 'Delete journal',
 36→            className: 'delete-button',
 37→            actionDelete: (e, journalId) => handleClickDeleteJournal(e, journalId),
 38→            icon:
