 48→            label: 'Edit journal',
 49→            className: 'edit-button',
 50→            actionEdit: (e, journalContent, journalId, journalTitle) => handleClickEdit(e, journalContent, journalId, journalTitle), // still in progress
 51→            icon: 
 52→            <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill="none">
 53→                <path d="M18.3785 8.44975L11.4637 15.3647C11.1845 15.6439 10.8289 15.8342 10.4417 15.9117L7.49994 16.5L8.08829 13.5582C8.16572 13.1711 8.35603 12.8155 8.63522 12.5363L15.5501 5.62132M18.3785 8.44975L19.7927 7.03553C20.1832 6.64501 20.1832 6.01184 19.7927 5.62132L18.3785 4.20711C17.988 3.81658 17.3548 3.81658 16.9643 4.20711L15.5501 5.62132M18.3785 8.44975L15.5501 5.62132" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 54→                <path d="M5 20H19" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 55→            </svg>
 56→        },
 57→        {
 58→            label: 'Only me',
 59→            className: 'only-me-bttn',
 60→            actionOnlyMe: (e, privacy, journalId) => {handleEditJournalPrivacy(e, privacy, journalId)},
 61→            icon: 
 62→            <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 16 16" fill="none">
 63→                <g fill="#000000">
 64→                    <path fillRule="evenodd" d="M5.58 7C5.835 5.124 6.667 3.335 8 1.836a10.074 10.074 0 011.806 2.878.75.75 0 101.388-.568 11.412 11.412 0 00-1.322-2.372A6.503 6.503 0 0114.5 8 .75.75 0 0016 8a8 8 0 10-11.31 7.285.75.75 0 10.622-1.365A6.504 6.504 0 011.519 8.5h2.503c.04.563.122 1.12.248 1.668a.75.75 0 101.462-.336c-.1-.438-.17-.883-.205-1.332H7A.75.75 0 007 7H5.58zM4.07 7H1.576a6.508 6.508 0 014.552-5.226A11.095 11.095 0 004.068 7z" clipRule="evenodd"/>
 65→                    <path d="M11.75 12.25a.75.75 0 00-1.5 0v.5a.75.75 0 001.5 0v-.5z"/>
 66→                    <path fillRule="evenodd" d="M8.518 9.012c.035-.627.13-1.235.366-1.738.174-.37.435-.704.816-.94C10.08 6.101 10.52 6 11 6c.48 0 .921.1 1.3.334.381.236.642.57.816.94.236.503.331 1.111.366 1.738A2.25 2.25 0 0115.5 11.25v2.5A2.25 2.25 0 0113.25 16h-4.5a2.25 2.25 0 01-2.25-2.25v-2.5a2.25 2.25 0 012.018-2.238zM10.022 9c.032-.481.102-.838.22-1.087a.662.662 0 01.245-.302c.09-.055.243-.111.513-.111s.423.056.513.111c.087.054.17.141.246.302.117.249.187.606.219 1.087h-1.956zm3.228 1.5a.75.75 0 01.75.75v2.5a.75.75 0 01-.75.75h-4.5a.75.75 0 01-.75-.75v-2.5a.75.75 0 01.75-.75h4.5z" clipRule="evenodd"/>
 67→                </g>
 68→            </svg>
 69→        },
 70→        {
 71→            label: 'public',
 72→            className: 'public-post-bttn',
 73→            actionPublic: (e, privacy, journalId) => {handleEditJournalPrivacy(e, privacy, journalId)},
 74→            icon:
 75→            <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 16 16" fill="none"><path fill="#000000" fillRule="evenodd" d="M8 0a8 8 0 100 16A8 8 0 008 0zM6.128 1.774A6.508 6.508 0 001.576 7H4.07a11.095 11.095 0 012.06-5.226zm3.744 0A11.096 11.096 0 0111.932 7h2.492a6.508 6.508 0 00-4.552-5.226zM10.42 7C10.165 5.124 9.333 3.335 8 1.836 6.667 3.335 5.835 5.124 5.58 7h4.84zM5.527 8.5h4.946C10.31 10.557 9.451 12.533 8 14.164 6.55 12.533 5.691 10.557 5.527 8.5zm-1.505 0H1.52a6.505 6.505 0 004.61 5.726C4.896 12.525 4.163 10.555 4.021 8.5zm5.85 5.726c1.231-1.701 1.964-3.671 2.106-5.726h2.503a6.505 6.505 0 01-4.61 5.726z" clipRule="evenodd"/></svg>
 76→        }
 77→    ]
 78→
 79→    const [showSettings, setShowSettings] = useState(null);
 80→    const [showConfirmationBttn, setShowConfirmationBttn] = useState(null);
 81→    const [journalData, setJournalData] = useState(null);
 82→    const [isDeletingJournal, setIsDeletingJournal] = useState(false);
 83→    const [journalIsDeleted, setJournalIsDeleted] = useState(false);
 84→    const [viewMode, setViewMode] = useState('grid');
 85→    const [showCaptionEditor, setShowCaptionEditor] = useState(null);
 86→    const [captionData, setCaptionData] = useState(null);
 87→    const [captionText, setCaptionText] = useState('');
 88→    const [isSavingCaption, setIsSavingCaption] = useState(false);
 89→    
 90→    const {
 91→        data,
 92→        fetchNextPage,
 93→        hasNextPage,
 94→        isFetchingNextPage,
 95→        isLoading,
 96→    } = useInfiniteQuery({
 97→        queryKey: ['userJournals', user?.userData?.[0].id],
 98→        queryFn: ({queryKey, pageParam}) => getUserJournals(pageParam, 5, queryKey[1], session?.access_token),
 99→        getNextPageParam: (lastPage) =>{
100→            if(lastPage.hasMore){
101→                const lastJournal = lastPage?.data[lastPage?.data.length - 1];
102→                return new Date(lastJournal.created_at).toISOString();
103→            } else {
104→                return undefined;
105→            }
106→        },
107→        enabled: !!user?.userData?.[0].id,
108→        refetchOnWindowFocus: false,
109→    })
110→
111→    
112→    const clickContent = handleCLickContent(navigate);
113→    const mutateViews = useAddViewsMutation(session);
114→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, canvasDoc = null) => {
115→        const formadata = new FormData();
116→
117→        formadata.append('journalId', journalId);
118→        mutateViews.mutate(formadata);
119→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, canvasDoc)
120→    }
121→
122→    const mutatePrivacy = useUpdateJournalPrivacyMutation(session);
123→    const handleEditJournalPrivacy = (e, privacy, journalId) =>{
124→        e.stopPropagation();
125→        const onlyme = privacy === 'public' ? 'private' : 'public'
126→        const formdata = new FormData();
127→
128→        formdata.append('journalId', journalId);
129→        formdata.append('privacy', onlyme);
130→        mutatePrivacy.mutate(formdata);    
131→    }
132→
133→    const handleClickSettings = (e, journalId) =>{
134→        e.stopPropagation();
135→        setShowSettings(showSettings === journalId ? null : journalId)
136→    }
137→
138→    const handleClickDeleteJournal = (e, journalId) =>{
139→        e.stopPropagation();
140→        setShowConfirmationBttn(showConfirmationBttn === journalId ? null : journalId)
141→        setShowSettings(null)
142→    }
143→
144→    const handleConfirmDeleteJournal = async(e, journalId, token, image_url) =>{
145→        e.stopPropagation();
146→
147→        const imageUrlArray = [image_url];
148→        const queryKey = ['userJournals', user?.userData?.[0].id];
149→        let previousUserJournals = null;
150→        // console.log({
151→        //     journalId: journalId,
152→        //     image_url: imageUrlArray,
153→        //     token: token
154→        // })
155→
156→        try {
157→            setIsDeletingJournal(true);
158→            previousUserJournals = queryClient.getQueryData(queryKey);
159→
160→            queryClient.setQueryData(queryKey, (old) => {
161→                if (!old || !Array.isArray(old.pages)) return old;
162→
163→                return {
164→                    ...old,
165→                    pages: old.pages.map((page) => ({
166→                        ...page,
167→                        data: Array.isArray(page?.data)
168→                            ? page.data.filter((journal) => journal?.id !== journalId)
169→                            : page?.data
170→                    }))
171→                };
172→            });
173→
174→            const deleteJournalPromise = deleteJournal(journalId, token,)
175→            const deleteImageJournalPromise = image_url ? deleteJournalImage(token, imageUrlArray) : Promise.resolve(null);
176→
177→            const [deletePostJournal, deletePostJournalImage] = await Promise.allSettled([
178→                deleteJournalPromise,
179→                deleteImageJournalPromise,
180→            ])
181→            if(deletePostJournal || deletePostJournalImage){
182→                console.log({deletePostJournal: deletePostJournal, deletePostJournalImage: deletePostJournalImage})
183→            }
184→
185→            if(deletePostJournal.status !== 'fulfilled'){
186→                queryClient.setQueryData(queryKey, previousUserJournals);
187→                throw deletePostJournal.reason || new Error('failed to delete journal');
188→            }
189→
190→            setJournalIsDeleted(true)
191→            queryClient.invalidateQueries({ queryKey: queryKey });
192→            queryClient.invalidateQueries({ queryKey: ['journals'] });
193→            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
194→
195→            setTimeout(() =>{
196→                setIsDeletingJournal(false)
197→                setJournalIsDeleted(false)
198→                setShowConfirmationBttn(null)
199→            }, 1500)
200→
201→        } catch (error) {
202→            if(previousUserJournals){
203→                queryClient.setQueryData(queryKey, previousUserJournals);
204→            }
205→            console.error("Error deleting journal:", error);
206→            setIsDeletingJournal(false);
207→        }
208→    }
209→
210→    const handleClickEdit = (e, journalContent, journalId, journalTitle) =>{
211→        e.stopPropagation();
212→        setShowSettings(null)
213→        const data = {
214→            content: journalContent,
215→            id: journalId,
216→            title: journalTitle
217→        }
218→        setJournalData(data);
219→        setShowEditor(showEditor === journalId ? null : journalId);
220→    }
221→
222→    const handleClickCloseEditor = () => {
223→        setShowEditor(null)
224→    }
225→
226→    const handleClickEditRepostCaption = (e, journalId, currentCaption) => {
227→        e.stopPropagation();
228→        setShowSettings(null);
229→        setCaptionData({id: journalId});
230→        setCaptionText(currentCaption || '');
231→        setShowCaptionEditor(journalId);
232→    }
233→
234→    const handleSaveRepostCaption = async() => {
235→        if(!captionData?.id || isSavingCaption) return;
236→        try {
237→            setIsSavingCaption(true);
238→            await updateRepostCaption(session?.access_token, {
239→                journalId: captionData.id,
240→                caption: captionText
241→            });
242→            queryClient.invalidateQueries({queryKey: ['userJournals']});
243→            queryClient.invalidateQueries({queryKey: ['journals']});
244→            queryClient.invalidateQueries({queryKey: ['visitedProfileJournals']});
245→            setShowCaptionEditor(null);
246→            setCaptionData(null);
247→            setCaptionText('');
248→        } catch (error) {
249→            console.error('failed to update repost caption:', error);
250→        } finally {
251→            setIsSavingCaption(false);
252→        }
253→    }
254→
255→    const handleCloseCaptionEditor = () => {
256→        setShowCaptionEditor(null);
257→        setCaptionData(null);
258→        setCaptionText('');
259→    }
260→
261→    useEffect(() =>{
262→        console.log(data)
263→    }, [data])
264→
265→    useEffect(() =>{
266→        const handleClickOutsideSettings = (e) => {
267→            e.stopPropagation();
268→            if(showSettings !== null && !e.target.closest('.user-post-settings')){
269→                setShowSettings(null)
270→            }
271→        }
272→        
273→        document.addEventListener('click', handleClickOutsideSettings);
274→
275→        return () => {
276→            document.removeEventListener('click', handleClickOutsideSettings)
277→        }
278→    }, [showSettings])
279→
280→
281→    const isLoadingMore = isFetchingNextPage || !hasNextPage
282→    useEffect(() =>{
283→        if(inView && !isLoadingMore){
284→            fetchNextPage();
285→        }
286→    }, [fetchNextPage, isLoadingMore, inView])
287→
288→    const handleToggleView = useCallback(() => {
289→        setViewMode((prev) => (prev === 'list' ? 'grid' : 'list'));
290→    }, []);
291→
292→
293→    const journals = data?.pages.flatMap((page) => page.data) || [];
294→    if(isLoading){
295→        return(
296→            <>
297→            <div className='profile-postcards-loading-container'>
298→                <MoonLoader loading={isLoading} color="var(--loader-color)" size={20} speedMultiplier={0.5}/>
299→            </div>
300→            </>
301→        )
302→    }
303→    if(data && journals?.length === 0){
304→        return(
305→            <div className='profile-postcards-loading-container'>
306→                No post available!
307→            </div>
308→        )
309→    }
310→    return(
311→        <>
312→        <div className='profile-postcards-parent-container'>
313→            <div className="postcards-header-row">
314→                <h2 className="postcards-heading">
315→                    Posts <span className="postcards-count">({journals.length})</span>
316→                </h2>
317→                <div className="postcards-header-actions">
318→                    <button
319→                        className={`postcards-view-toggle-btn ${viewMode === 'grid' ? 'is-active' : ''}`}
320→                        onClick={handleToggleView}
321→                        title={viewMode === 'grid' ? 'Switch to list' : 'Switch to grid'}
322→                    >
323→                        {viewMode === 'grid' ? (
324→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-520v-320h320v320H120Zm0 400v-320h320v320H120Zm400-400v-320h320v320H520Zm0 400v-320h320v320H520Z"/></svg>
325→                        ) : (
326→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-200v-560h720v560H120Z"/></svg>
327→                        )}
328→                    </button>
329→                </div>
330→            </div>
331→
332→            {viewMode === 'grid' ? (
333→                <div className="postcards-grid-view">
334→                    {journals.map((journal) => {
335→                        const isCanvasPost = journal?.post_type === 'canvas';
336→                        const parsedContent = ParseContent(journal?.content);
337→                        const canvasPreview = isCanvasPost ? getCanvasPreview(journal?.canvas_doc) : null;
338→                        const wholeText = isCanvasPost ? canvasPreview?.wholeText || '' : parsedContent?.wholeText || '';
339→                        const previewText = isCanvasPost ? canvasPreview?.slicedText || '' : parsedContent?.slicedText || '';
340→                        const thumbnail = isCanvasPost ? null : parsedContent?.firstImage?.src;
341→                        return (
342→                            <motion.div
343→                                key={journal.id}
344→                                className={`postcards-grid-item${isCanvasPost ? ' is-canvas-card' : ''}`}
345→                                initial={{ opacity: 0, scale: 0.95 }}
346→                                animate={{ opacity: 1, scale: 1 }}
347→                                transition={{ duration: 0.25, ease: 'easeOut' }}
348→                                onClick={(e) => viewContent(e, journal.content, wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0].count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count, journal.users.badge, journal?.post_type, journal?.canvas_doc)}
349→                            >
350→                                {showConfirmationBttn === journal.id && (
351→                                    <AnimatePresence>
352→                                    <div className="confirmation-delete-bg">
353→                                        {journalIsDeleted && (
354→                                            <motion.div
355→                                                className='journal-is-deleted-message-container'
356→                                                initial={{opacity: 0, scale: 0}}
357→                                                animate={{opacity: 1, scale: 1, transition:{type: 'tween', duration: 0.1}}}
358→                                                exit={{y: -900, opacity: 0, transition:{type:'tween', duration: 0.5, ease: 'easeOut'}}}
359→                                            >
360→                                                Journal deleted successfuly!
361→                                                <svg xmlns="http://www.w3.org/2000/svg" height="44px" viewBox="0 -960 960 960" width="44px" fill="#00d61dff"><path d="M268-240 42-466l57-56 170 170 56 56-57 56Zm226 0L268-466l56-57 170 170 368-368 56 57-424 424Zm0-226-57-56 198-198 57 56-198 198Z"/></svg>
362→                                            </motion.div>
363→                                        )}
364→
365→                                        {isDeletingJournal && (
366→                                            <div className='delete-journal-loader-container'>
367→                                                <FadeLoader loading={isDeletingJournal} speedMultiplier={2}/>
368→                                                <p style={{margin: '0', padding: '0', fontWeight: 760}}>Deleting the journal...</p>
369→                                            </div>
370→                                        )}
371→
372→                                        <motion.div
373→                                            className="confirmation-delete-container"
374→                                            initial={{opacity:0 ,scale:0}}
375→                                            animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.1}}}
376→                                            exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.1}}}
377→                                        >
378→                                            <div className="confirmation-delete-heading">
379→                                                Do you want to delete the journal?
380→                                            </div>
381→                                            <div className="confirm-buttons-container">
382→                                                <div onClick={(e) => handleConfirmDeleteJournal(e, journal.id, session?.access_token, parsedContent?.firstImage?.src)} className="confirm-buttons-yes">Yes</div>
383→                                                <div onClick={() => setShowConfirmationBttn(null)} className="confirm-buttons-cancel">Cancel</div>
384→                                            </div>
385→                                        </motion.div>
386→                                    </div>
387→                                    </AnimatePresence>
388→                                )}
389→
390→                                {isCanvasPost ? (
391→                                    <div className="postcards-grid-img-wrap">
392→                                        <CanvasPreview canvasDoc={journal?.canvas_doc} />
393→                                    </div>
394→                                ) : thumbnail ? (
395→                                    <div className="postcards-grid-img-wrap">
396→                                        <img className="postcards-grid-thumb" src={thumbnail} alt={journal?.title ? `${journal.title} cover image` : "Post cover image"} loading="lazy" onError={handleImageFallback} />
397→                                    </div>
398→                                ) : null}
399→                                <div className="postcards-grid-body">
400→                                    <h3 className="postcards-grid-title">{journal.title.length > 32 ? `${journal.title.substring(0, 32)}...` : journal.title}</h3>
401→                                    {previewText && (
402→                                        <p className="postcards-grid-snippet">{previewText.length > 50 ? `${previewText.substring(0, 50)}...` : previewText}</p>
403→                                    )}
404→                                    <div className="postcards-grid-body-footer">
405→                                        <div className="user-post-privacy">
406→                                            {journal.privacy === 'public' && (
407→                                                <svg xmlns="http://www.w3.org/2000/svg" width="14px" height="14px" viewBox="0 0 16 16" fill="none"><path fill="currentColor" fillRule="evenodd" d="M8 0a8 8 0 100 16A8 8 0 008 0zM6.128 1.774A6.508 6.508 0 001.576 7H4.07a11.095 11.095 0 012.06-5.226zm3.744 0A11.096 11.096 0 0111.932 7h2.492a6.508 6.508 0 00-4.552-5.226zM10.42 7C10.165 5.124 9.333 3.335 8 1.836 6.667 3.335 5.835 5.124 5.58 7h4.84zM5.527 8.5h4.946C10.31 10.557 9.451 12.533 8 14.164 6.55 12.533 5.691 10.557 5.527 8.5zm-1.505 0H1.52a6.505 6.505 0 004.61 5.726C4.896 12.525 4.163 10.555 4.021 8.5zm5.85 5.726c1.231-1.701 1.964-3.671 2.106-5.726h2.503a6.505 6.505 0 01-4.61 5.726z" clipRule="evenodd"/></svg>
408→                                            )}
