 12→/**
 13→ * Batch-fetch public user profiles for a list of author IDs.
 14→ */
 15→const fetchAuthorProfiles = async (authorIds) => {
 16→    const unique = [...new Set(authorIds.filter(Boolean))];
 17→    if (unique.length === 0) return {};
 18→
 19→    const { data, error } = await supabase
 20→        .from('users')
 21→        .select('id, name, image_url, username, badge')
 22→        .in('id', unique);
 23→
 24→    if (error) {
 25→        console.error('supabase error fetching author profiles:', error.message);
 26→        return {};
 27→    }
 28→
 29→    const map = {};
 30→    (data || []).forEach(u => { map[u.id] = u; });
 31→    return map;
 32→};
