 34→export const createStoryService = async (userId, title, description, status, privacy, tags, coverFile) => {
 35→    if (!userId) {
 36→        throw { status: 400, error: 'userId is undefined' };
 37→    }
 38→    if (!title || typeof title !== 'string' || title.trim().length === 0) {
 39→        throw { status: 400, error: 'title is required' };
 40→    }
 41→    if (title.length > 200) {
 42→        throw { status: 400, error: 'title must be 200 characters or less' };
 43→    }
 44→    if (description && description.length > 2000) {
 45→        throw { status: 400, error: 'description must be 2000 characters or less' };
 46→    }
 47→
 48→    const validStatuses = ['ongoing', 'completed', 'hiatus'];
 49→    const validPrivacy = ['public', 'private'];
 50→    const storyStatus = validStatuses.includes(status) ? status : 'ongoing';
 51→    const storyPrivacy = validPrivacy.includes(privacy) ? privacy : 'public';
 52→
 53→    let parsedTags = [];
 54→    if (tags) {
 55→        try {
 56→            parsedTags = typeof tags === 'string' ? JSON.parse(tags) : tags;
 57→            if (!Array.isArray(parsedTags)) parsedTags = [];
 58→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
 59→        } catch {
 60→            parsedTags = [];
 61→        }
 62→    }
 63→
 64→    let coverUrl = null;
 65→    if (coverFile) {
 66→        coverUrl = await imageUploader(coverFile, userId, 'story-covers');
 67→    }
 68→
 69→    const embedding = await GenerateEmbeddings(title.trim(), (description || '').trim());
 70→    if (!embedding || !Array.isArray(embedding) || embedding.length === 0) {
 71→        throw { status: 400, error: 'failed to generate story embedding' };
 72→    }
 73→
 74→    const { data, error } = await supabase
 75→        .from('stories')
 76→        .insert({
 77→            author_id: userId,
 78→            title: title.trim(),
 79→            description: (description || '').trim(),
 80→            cover_url: coverUrl,
 81→            status: storyStatus,
 82→            privacy: storyPrivacy,
 83→            tags: parsedTags,
 84→            embedding,
 85→        })
 86→        .select('*')
 87→        .single();
 88→
 89→    if (error) {
 90→        console.error('supabase error creating story:', error.message);
 91→        throw { status: 500, error: 'failed to create story' };
 92→    }
 93→
 94→    return stripEmbedding(data);
 95→};
