102→        .select('*')
103→        .eq('privacy', 'public')
104→        .order('created_at', { ascending: false })
105→        .limit(parsedLimit + 1);
106→
107→    if (before) {
108→        query = query.lt('created_at', before);
109→    }
110→    if (status && ['ongoing', 'completed', 'hiatus'].includes(status)) {
111→        query = query.eq('status', status);
112→    }
113→    if (tag) {
114→        query = query.contains('tags', [tag]);
115→    }
116→
117→    const { data, error } = await query;
118→
119→    if (error) {
120→        console.error('supabase error fetching stories:', error.message);
121→        throw { status: 500, error: 'failed to fetch stories' };
122→    }
123→
124→    if (!data || data.length === 0) {
125→        return { data: [], hasMore: false };
126→    }
127→
128→    // Batch-fetch author profiles
129→    const authorMap = await fetchAuthorProfiles(data.map(s => s.author_id));
130→
131→    // Fetch user interaction flags if logged in
132→    let userVotedSet = new Set();
133→    let userLibrarySet = new Set();
134→
135→    if (userId) {
136→        const storyIds = data.map(s => s.id);
137→        const [votes, library] = await Promise.all([
138→            supabase.from('story_votes').select('story_id').in('story_id', storyIds).eq('user_id', userId),
139→            supabase.from('story_library').select('story_id').in('story_id', storyIds).eq('user_id', userId),
140→        ]);
141→
142→        if (votes.data) userVotedSet = new Set(votes.data.map(v => v.story_id));
143→        if (library.data) userLibrarySet = new Set(library.data.map(l => l.story_id));
144→    }
145→
146→    const formatted = data.map(story => ({
147→        ...stripEmbedding(story),
148→        users: authorMap[story.author_id] || null,
149→        has_voted: userVotedSet.has(story.id),
150→        in_library: userLibrarySet.has(story.id),
151→    }));
152→
153→    const hasMore = data.length > parsedLimit;
154→    const sliced = hasMore ? formatted.slice(0, parsedLimit) : formatted;
155→
156→    return { data: sliced, hasMore };
157→};
