159→export const getStoryByIdService = async (storyId, userId) => {
160→    if (!storyId) {
161→        throw { status: 400, error: 'storyId is required' };
162→    }
163→
164→    const { data: story, error } = await supabase
165→        .from('stories')
166→        .select('*')
167→        .eq('id', storyId)
168→        .single();
169→
170→    if (error || !story) {
171→        console.error('supabase error fetching story:', error?.message);
172→        throw { status: 404, error: 'story not found' };
173→    }
174→
175→    // Non-author can't see private stories
176→    if (story.privacy === 'private' && story.author_id !== userId) {
177→        throw { status: 404, error: 'story not found' };
178→    }
179→
180→    // Fetch author profile + chapters in parallel
181→    const [authorMap, chapResult] = await Promise.all([
182→        fetchAuthorProfiles([story.author_id]),
183→        supabase
184→            .from('chapters')
185→            .select('id, chapter_number, title, word_count, status, published_at, created_at')
186→            .eq('story_id', storyId)
187→            .order('chapter_number', { ascending: true }),
188→    ]);
189→
190→    if (chapResult.error) {
191→        console.error('supabase error fetching chapters:', chapResult.error.message);
192→    }
193→
194→    // Filter chapters for non-authors
195→    const isAuthor = story.author_id === userId;
196→    const chapters = chapResult.data || [];
197→    const visibleChapters = isAuthor
198→        ? chapters
199→        : chapters.filter(c => c.status === 'published');
200→
201→    // Fetch user flags
202→    let hasVoted = false;
203→    let inLibrary = false;
204→    let readingProgress = null;
205→
206→    if (userId) {
207→        const [voteRes, libRes, progressRes] = await Promise.all([
208→            supabase.from('story_votes').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
209→            supabase.from('story_library').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
210→            supabase.from('reading_progress').select('chapter_id, scroll_position, last_read_at').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
211→        ]);
212→
213→        hasVoted = !!voteRes.data;
214→        inLibrary = !!libRes.data;
215→        readingProgress = progressRes.data || null;
216→    }
217→
218→    return {
219→        ...stripEmbedding(story),
220→        users: authorMap[story.author_id] || null,
221→        chapters: visibleChapters,
222→        has_voted: hasVoted,
223→        in_library: inLibrary,
224→        reading_progress: readingProgress,
225→        is_author: isAuthor,
226→    };
227→};
