## Analysis Report: Infinite Query Patterns & Pagination Strategy

### 1. **ProfilePostCards.jsx - Exact Infinite Query Pattern**

**File:** `/c/Users/johnm/iskrib_v3/client/src/components/HomePage/postCards/ProfilePostCards/ProfilePostCards.jsx` (Lines 90-109)

```javascript
const {
    data,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
    isLoading,
} = useInfiniteQuery({
    queryKey: ['userJournals', user?.userData?.[0].id],
    queryFn: ({queryKey, pageParam}) => getUserJournals(pageParam, 5, queryKey[1], session?.access_token),
    getNextPageParam: (lastPage) =>{
        if(lastPage.hasMore){
            const lastJournal = lastPage?.data[lastPage?.data.length - 1];
            return new Date(lastJournal.created_at).toISOString();
        } else {
            return undefined;
        }
    },
    enabled: !!user?.userData?.[0].id,
    refetchOnWindowFocus: false,
})
```

**Key Pattern Details:**
- **queryFn signature:** `({queryKey, pageParam}) => getUserJournals(pageParam, 5, queryKey[1], session?.access_token)`
  - `pageParam` is the cursor (ISO timestamp on first load, undefined)
  - `queryKey[1]` contains the userId
  - Hardcoded page size: `5` items

- **getNextPageParam:** Returns `created_at` ISO string from the last journal if `hasMore` is true, otherwise undefined

- **Cursor Strategy:** `created_at` timestamp-based (ISO 8601 format). First page has `pageParam` as undefined.

- **Page Flattening (Line 293):**
  ```javascript
  const journals = data?.pages.flatMap((page) => page.data) || [];
  ```

- **IntersectionObserver Sentinel (Lines 29-31, 671, 281-286):**
  ```javascript
  const {ref, inView} = useInView({ threshold: 0.2 })

  // In return JSX (Line 671):
  <div ref={ref} className='in-view-container'>
      {isFetchingNextPage && (
          <MoonLoader loading={isFetchingNextPage} color="var(--loader-color)" size={20}/>
      )}
  </div>

  // Trigger fetching (Lines 281-286):
  useEffect(() =>{
      const isLoadingMore = isFetchingNextPage || !hasNextPage
      useEffect(() =>{
          if(inView && !isLoadingMore){
              fetchNextPage();
          }
      }, [fetchNextPage, isLoadingMore, inView])
  }, [data])
  ```

---

### 2. **Backend getUserStoriesService - Current Pagination Status**

**File:** `/c/Users/johnm/iskrib_v3/server/services/storyService.js` (Lines 359-381)

```javascript
export const getUserStoriesService = async (targetUserId) => {
    if (!targetUserId) {
        throw { status: 400, error: 'userId is required' };
    }

    const { data, error } = await supabase
        .from('stories')
        .select('*')
        .eq('author_id', targetUserId)
        .eq('privacy', 'public')
        .order('created_at', { ascending: false });

    if (error) {
        console.error('supabase error fetching user stories:', error.message);
        throw { status: 500, error: 'failed to fetch user stories' };
    }

    // Batch-fetch author profiles
    const authorMap = await fetchAuthorProfiles((data || []).map(s => s.author_id));
    const formatted = (data || []).map(s => ({ ...stripEmbedding(s), users: authorMap[s.author_id] || null }));

    return formatted;
};
```

**STATUS:** ❌ **Does NOT support pagination** 
- No `limit` parameter
- No `before` (cursor) parameter
- Returns entire array of all user's public stories
- Returns raw array, not `{ data, hasMore }` structure

---

### 3. **Backend getStoriesService - Pagination Implementation**

**File:** `/c/Users/johnm/iskrib_v3/server/services/storyService.js` (Lines 97-157)

```javascript
export const getStoriesService = async (limit, before, status, tag, userId) => {
    const parsedLimit = Math.min(Math.max(parseInt(limit) || 10, 1), 20);

    let query = supabase
        .from('stories')
        .select('*')
        .eq('privacy', 'public')
        .order('created_at', { ascending: false })
        .limit(parsedLimit + 1);  // +1 to detect hasMore

    if (before) {
        query = query.lt('created_at', before);  // Timestamp cursor
    }
    if (status && ['ongoing', 'completed', 'hiatus'].includes(status)) {
        query = query.eq('status', status);
    }
    if (tag) {
        query = query.contains('tags', [tag]);
    }

    const { data, error } = await query;

    if (error) {
        console.error('supabase error fetching stories:', error.message);
        throw { status: 500, error: 'failed to fetch stories' };
    }

    if (!data || data.length === 0) {
        return { data: [], hasMore: false };
    }

    // ... author profiles & user interactions ...

    const hasMore = data.length > parsedLimit;
    const sliced = hasMore ? formatted.slice(0, parsedLimit) : formatted;

    return { data: sliced, hasMore };
};
```

**STATUS:** ✅ **Full pagination support**
- **Parameters:** `limit` (default 10, capped at 20), `before` (created_at timestamp cursor)
- **Strategy:** `created_at` timestamp-based cursor (`.lt('created_at', before)`)
- **Overflow detection:** Fetches `parsedLimit + 1` to detect `hasMore`
- **Response format:** `{ data: [...], hasMore: boolean }`

---

### 4. **Client API Functions - Parameter Comparison**

**File:** `/c/Users/johnm/iskrib_v3/client/API/StoryApi.js`

**getStories (Line 22-41):**
```javascript
export const getStories = async (limit = 10, before = null, status = null, tag = null, token = null) => {
    const params = new URLSearchParams();
    params.set('limit', limit);
    if (before) params.set('before', before);
    if (status) params.set('status', status);
    if (tag) params.set('tag', tag);

    const headers = {};
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const response = await apiRequest(`${BASE_URL}/stories?${params}`, {
        method: 'GET',
        headers,
    });
    // ...
    return response.json();
};
```

**getUserStories (Line 119-132):**
```javascript
export const getUserStories = async (userId, token = null) => {
    const headers = {};
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const response = await apiRequest(`${BASE_URL}/stories/user/${userId}`, {
        method: 'GET',
        headers,
    });
    // ...
    return response.json();
};
```

**Comparison:**
- `getStories`: Accepts `limit` and `before` cursor params ✅
- `getUserStories`: NO pagination params ❌ (just userId in URL path)

